@Configuration
class SecurityConfig {
    @Bean
    SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf.ignoringRequestMatchers("/saml/acs"))
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/saml/acs", "/error").permitAll()
                .anyRequest().authenticated()
            )
            .formLogin(form -> form.disable())
            .httpBasic(Customizer.withDefaults());
        return http.build();
    }
}

@Controller
class HomeController {
    @GetMapping(value = "/", produces = MediaType.TEXT_HTML_VALUE)
    public String home(HttpServletRequest request, Map<String, Object> model) {
        HttpSession session = request.getSession(false);
        if (session == null || session.getAttribute("SAML_USER") == null) {
            return "redirect:/profile";
        }
        return "redirect:/profile";
    }

    @GetMapping(value = "/profile", produces = MediaType.TEXT_HTML_VALUE)
    public org.springframework.http.ResponseEntity<String> profile(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session == null) {
            return org.springframework.http.ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("No session");
        }
        Object user = session.getAttribute("SAML_USER");
        Object attrs = session.getAttribute("SAML_ATTRIBUTES");
        if (user == null) {
            return org.springframework.http.ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("Not authenticated");
        }
        return org.springframework.http.ResponseEntity.ok("user=" + user + "\nattributes=" + attrs);
    }
}

@Controller
class SamlAcsController {
    private final SamlResponseProcessor processor;

    SamlAcsController(SamlResponseProcessor processor) {
        this.processor = processor;
    }

    @PostMapping(value = "/saml/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public org.springframework.http.ResponseEntity<String> acs(
            @RequestParam("SAMLResponse") String samlResponse,
            @RequestParam(value = "RelayState", required = false) String relayState,
            HttpServletRequest request
    ) {
        SamlPrincipal principal = processor.processPostBindingResponse(samlResponse);
        HttpSession session = request.getSession(true);
        session.setAttribute("SAML_NAME_ID", principal.getNameId());
        session.setAttribute("SAML_USER", principal.getUsername());
        session.setAttribute("SAML_SESSION_INDEX", principal.getSessionIndex());
        session.setAttribute("SAML_ATTRIBUTES", principal.getAttributes());
        session.setAttribute("SAML_AUTH_INSTANT", principal.getAuthInstant());
        session.setAttribute("RELAY_STATE", relayState);

        Authentication authentication = new SamlAuthenticationToken(principal);
        org.springframework.security.core.context.SecurityContext context =
                org.springframework.security.core.context.SecurityContextHolder.createEmptyContext();
        context.setAuthentication(authentication);
        org.springframework.security.core.context.SecurityContextHolder.setContext(context);
        session.setAttribute(
                org.springframework.security.web.context.HttpSessionSecurityContextRepository.SPRING_SECURITY_CONTEXT_KEY,
                context
        );

        return org.springframework.http.ResponseEntity.ok("SAML authentication successful for " + principal.getUsername());
    }
}

@Component
class SamlResponseProcessor {
    private static final String NS_SAML_PROTOCOL = "urn:oasis:names:tc:SAML:2.0:protocol";
    private static final String NS_SAML_ASSERTION = "urn:oasis:names:tc:SAML:2.0:assertion";
    private static final String NS_DS = Constants.SignatureSpecNS;

    private final SamlSettings settings;

    SamlResponseProcessor(SamlSettings settings) {
        this.settings = settings;
    }

    public SamlPrincipal processPostBindingResponse(String base64Response) {
        try {
            byte[] decoded = Base64Utils.decodeFromString(base64Response);
            Document document = parseXmlSecurely(decoded);

            Element responseElement = document.getDocumentElement();
            if (!NS_SAML_PROTOCOL.equals(responseElement.getNamespaceURI()) || !"Response".equals(responseElement.getLocalName())) {
                throw new SamlProcessingException("Invalid SAML Response root element");
            }

            String destination = responseElement.getAttribute("Destination");
            if (settings.getAcsUrl() != null && !settings.getAcsUrl().isBlank() && !settings.getAcsUrl().equals(destination)) {
                throw new SamlProcessingException("Invalid Destination");
            }

            String statusCode = evaluateString(document, "/*[local-name()='Response']/*[local-name()='Status']/*[local-name()='StatusCode']/@Value");
            if (!"urn:oasis:names:tc:SAML:2.0:status:Success".equals(statusCode)) {
                throw new SamlProcessingException("SAML Response status is not success");
            }

            Element assertion = firstElement(document, "//*[local-name()='Assertion' and namespace-uri()='" + NS_SAML_ASSERTION + "']");
            if (assertion == null) {
                throw new SamlProcessingException("No Assertion found");
            }

            if (settings.isRequireSignatureValidation()) {
                boolean responseSigValid = verifySignatureIfPresent(responseElement);
                boolean assertionSigValid = verifySignatureIfPresent(assertion);
                if (!responseSigValid && !assertionSigValid) {
                    throw new SamlProcessingException("No valid XML signature found on Response or Assertion");
                }
            }

            validateConditions(document);
            validateAudience(document);
            validateSubjectConfirmation(document);

            String issuer = evaluateString(document, "string((/*[local-name()='Response']/*[local-name()='Issuer'])[1] | (//*[local-name()='Assertion']/*[local-name()='Issuer'])[1])");
            if (settings.getIdpEntityId() != null && !settings.getIdpEntityId().isBlank() && !settings.getIdpEntityId().equals(issuer)) {
                throw new SamlProcessingException("Unexpected issuer");
            }

            String nameId = evaluateString(document, "string(//*[local-name()='Assertion']/*[local-name()='Subject']/*[local-name()='NameID'][1])");
            if (nameId == null || nameId.isBlank()) {
                throw new SamlProcessingException("Missing NameID");
            }

            String sessionIndex = evaluateString(document, "string(//*[local-name()='AuthnStatement'][1]/@SessionIndex)");
            String authInstant = evaluateString(document, "string(//*[local-name()='AuthnStatement'][1]/@AuthnInstant)");

            Map<String, List<String>> attributes = extractAttributes(document);
            String username = resolveUsername(nameId, attributes);

            return new SamlPrincipal(username, nameId, sessionIndex, authInstant, issuer, attributes);
        } catch (SamlProcessingException e) {
            throw e;
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to process SAML response", e);
        }
    }

    private String resolveUsername(String nameId, Map<String, List<String>> attributes) {
        for (String key : settings.getUsernameAttributeCandidates()) {
            List<String> values = attributes.get(key);
            if (values != null && !values.isEmpty() && values.get(0) != null && !values.get(0).isBlank()) {
                return values.get(0);
            }
        }
        return nameId;
    }

    private void validateConditions(Document document) throws Exception {
        String notBeforeStr = evaluateString(document, "string(//*[local-name()='Assertion']/*[local-name()='Conditions'][1]/@NotBefore)");
        String notOnOrAfterStr = evaluateString(document, "string(//*[local-name()='Assertion']/*[local-name()='Conditions'][1]/@NotOnOrAfter)");
        Instant now = Instant.now();

        if (notBeforeStr != null && !notBeforeStr.isBlank()) {
            Instant notBefore = parseInstant(notBeforeStr);
            if (now.plusSeconds(settings.getClockSkewSeconds()).isBefore(notBefore)) {
                throw new SamlProcessingException("Assertion not yet valid");
            }
        }

        if (notOnOrAfterStr != null && !notOnOrAfterStr.isBlank()) {
            Instant notOnOrAfter = parseInstant(notOnOrAfterStr);
            if (!now.minusSeconds(settings.getClockSkewSeconds()).isBefore(notOnOrAfter)) {
                throw new SamlProcessingException("Assertion expired");
            }
        }
    }

    private void validateAudience(Document document) throws Exception {
        String audience = evaluateString(document, "string(//*[local-name()='AudienceRestriction']/*[local-name()='Audience'][1])");
        if (settings.getSpEntityId() != null && !settings.getSpEntityId().isBlank()) {
            if (audience == null || audience.isBlank() || !settings.getSpEntityId().equals(audience)) {
                throw new SamlProcessingException("Audience restriction validation failed");
            }
        }
    }

    private void validateSubjectConfirmation(Document document) throws Exception {
        NodeList nodes = evaluateNodeList(document, "//*[local-name()='SubjectConfirmation' and @Method='urn:oasis:names:tc:SAML:2.0:cm:bearer']/*[local-name()='SubjectConfirmationData']");
        if (nodes == null || nodes.getLength() == 0) {
            return;
        }

        Instant now = Instant.now();
        boolean valid = false;
        for (int i = 0; i < nodes.getLength(); i++) {
            Element scd = (Element) nodes.item(i);
            String recipient = scd.getAttribute("Recipient");
            String inResponseTo = scd.getAttribute("InResponseTo");
            String noa = scd.getAttribute("NotOnOrAfter");

            boolean recipientOk = settings.getAcsUrl() == null || settings.getAcsUrl().isBlank() || settings.getAcsUrl().equals(recipient);
            boolean inResponseToOk = settings.getExpectedInResponseTo() == null || settings.getExpectedInResponseTo().isBlank()
                    || settings.getExpectedInResponseTo().equals(inResponseTo);
            boolean timeOk = true;
            if (noa != null && !noa.isBlank()) {
                Instant notOnOrAfter = parseInstant(noa);
                timeOk = now.minusSeconds(settings.getClockSkewSeconds()).isBefore(notOnOrAfter);
            }

            if (recipientOk && inResponseToOk && timeOk) {
                valid = true;
                break;
            }
        }

        if (!valid) {
            throw new SamlProcessingException("SubjectConfirmation validation failed");
        }
    }

    private Map<String, List<String>> extractAttributes(Document document) throws Exception {
        Map<String, List<String>> result = new LinkedHashMap<>();
        NodeList attributeNodes = evaluateNodeList(document, "//*[local-name()='AttributeStatement']/*[local-name()='Attribute']");
        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Element attr = (Element) attributeNodes.item(i);
            String name = attr.getAttribute("Name");
            if (name == null || name.isBlank()) {
                name = attr.getAttribute("FriendlyName");
            }
            if (name == null || name.isBlank()) {
                continue;
            }
            NodeList values = attr.getElementsByTagNameNS(NS_SAML_ASSERTION, "AttributeValue");
            List<String> collected = new ArrayList<>();
            for (int j = 0; j < values.getLength(); j++) {
                collected.add(values.item(j).getTextContent().trim());
            }
            result.put(name, collected);
        }
        return result;
    }

    private boolean verifySignatureIfPresent(Element signedElement) throws Exception {
        Element sigElement = firstChildElementNS(signedElement, NS_DS, "Signature");
        if (sigElement == null) {
            return false;
        }

        X509Certificate certificate = settings.getIdpCertificate();
        if (certificate == null) {
            throw new SamlProcessingException("IdP certificate not configured");
        }

        XMLSignature signature = new XMLSignature(sigElement, "");
        PublicKey publicKey = certificate.getPublicKey();
        boolean valid = signature.checkSignatureValue(publicKey);
        if (!valid) {
            throw new SamlProcessingException("Invalid XML signature");
        }
        return true;
    }

    private Document parseXmlSecurely(byte[] xmlBytes) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");
        factory.setExpandEntityReferences(false);
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(new ByteArrayInputStream(xmlBytes));
        document.getDocumentElement().normalize();
        return document;
    }

    private String evaluateString(Document document, String expression) throws Exception {
        XPath xpath = xpath();
        return xpath.evaluate(expression, document);
    }

    private NodeList evaluateNodeList(Document document, String expression) throws Exception {
        XPath xpath = xpath();
        return (NodeList) xpath.evaluate(expression, document, XPathConstants.NODESET);
    }

    private Element firstElement(Document document, String expression) throws Exception {
        XPath xpath = xpath();
        return (Element) xpath.evaluate(expression, document, XPathConstants.NODE);
    }

    private XPath xpath() {
        XPath xpath = XPathFactory.newInstance().newXPath();
        xpath.setNamespaceContext(new NamespaceContext() {
            @Override
            public String getNamespaceURI(String prefix) {
                if ("samlp".equals(prefix)) return NS_SAML_PROTOCOL;
                if ("saml".equals(prefix)) return NS_SAML_ASSERTION;
                if ("ds".equals(prefix)) return NS_DS;
                return XMLConstants.NULL_NS_URI;
            }

            @Override
            public String getPrefix(String namespaceURI) {
                return null;
            }

            @Override
            public Iterator<String> getPrefixes(String namespaceURI) {
                return Collections.emptyIterator();
            }
        });
        return xpath;
    }

    private Instant parseInstant(String value) {
        try {
            return Instant.parse(value);
        } catch (DateTimeParseException e) {
            throw new SamlProcessingException("Invalid timestamp: " + value, e);
        }
    }

    private Element firstChildElementNS(Element parent, String ns, String localName) {
        Node child = parent.getFirstChild();
        while (child != null) {
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element e = (Element) child;
                if (Objects.equals(ns, e.getNamespaceURI()) && Objects.equals(localName, e.getLocalName())) {
                    return e;
                }
            }
            child = child.getNextSibling();
        }
        return null;
    }
}

