class SamlPrincipal {
    private final String username;
    private final String nameId;
    private final String sessionIndex;
    private final String authInstant;
    private final String issuer;
    private final Map<String, List<String>> attributes;

    SamlPrincipal(String username, String nameId, String sessionIndex, String authInstant, String issuer, Map<String, List<String>> attributes) {
        this.username = username;
        this.nameId = nameId;
        this.sessionIndex = sessionIndex;
        this.authInstant = authInstant;
        this.issuer = issuer;
        this.attributes = Collections.unmodifiableMap(new LinkedHashMap<>(attributes));
    }

    public String getUsername() {
        return username;
    }

    public String getNameId() {
        return nameId;
    }

    public String getSessionIndex() {
        return sessionIndex;
    }

    public String getAuthInstant() {
        return authInstant;
    }

    public String getIssuer() {
        return issuer;
    }

    public Map<String, List<String>> getAttributes() {
        return attributes;
    }
}

class SamlAuthenticationToken extends AbstractAuthenticationToken {
    private final SamlPrincipal principal;

    SamlAuthenticationToken(SamlPrincipal principal) {
        super(Collections.singletonList(new SimpleGrantedAuthority("ROLE_USER")));
        this.principal = principal;
        setAuthenticated(true);
    }

    @Override
    public Object getCredentials() {
        return "";
    }

    @Override
    public Object getPrincipal() {
        return principal;
    }

    @Override
    public String getName() {
        return principal.getUsername();
    }
}

class SamlProcessingException extends RuntimeException {
    SamlProcessingException(String message) {
        super(message);
    }

    SamlProcessingException(String message, Throwable cause) {
        super(message, cause);
    }
}